#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#define NPAIR 32
#define SIGP 6            /* pairs used in signature: indices 0..SIGP-1 */
#define DLEN (SIGP-1)     /* signature vector length */
#define NSEED (1<<20)

static uint32_t expand(uint32_t key){ key&=0xFFFFF; return key ^ (key<<16) ^ (key*12345u); }

static uint8_t rotl2(uint8_t t){ return (uint8_t)((t<<2)|(t>>6)); }
static uint8_t rotr2(uint8_t t){ return (uint8_t)((t>>2)|(t<<6)); }
static uint8_t g_function(uint8_t a,uint8_t b,uint8_t x){ return rotl2((uint8_t)(a+b+x)); }

static uint32_t f_function(uint32_t v){
    uint8_t x0=v&0xff,x1=(v>>8)&0xff,x2=(v>>16)&0xff,x3=(v>>24)&0xff,y0,y1,y2,y3;
    y2=g_function(x3^x2, x1^x0, 1);
    y3=g_function(x3, y2, 0);
    y1=g_function(x1^x0, y2, 0);
    y0=g_function(x0, y1, 1);
    return (uint32_t)y0 | ((uint32_t)y1<<8) | ((uint32_t)y2<<16) | ((uint32_t)y3<<24);
}
/* inverse of f_function */
static uint32_t finv(uint32_t v){
    uint8_t y0=v&0xff,y1=(v>>8)&0xff,y2=(v>>16)&0xff,y3=(v>>24)&0xff;
    uint8_t x0,x1,x2,x3,x1x0,x3x2;
    x3   = (uint8_t)(rotr2(y3) - y2);
    x1x0 = (uint8_t)(rotr2(y1) - y2);
    x3x2 = (uint8_t)(rotr2(y2) - x1x0 - 1);
    x2   = (uint8_t)(x3 ^ x3x2);
    x0   = (uint8_t)(rotr2(y0) - y1 - 1);
    x1   = (uint8_t)(x1x0 ^ x0);
    return (uint32_t)x0 | ((uint32_t)x1<<8) | ((uint32_t)x2<<16) | ((uint32_t)x3<<24);
}

static uint32_t P_L[NPAIR],P_R[NPAIR],C_L[NPAIR],C_R[NPAIR];
static uint32_t L0[NPAIR],R0[NPAIR],L4[NPAIR],R4[NPAIR];

typedef struct { uint32_t d[DLEN]; uint32_t seed; } Ent;
static Ent *left, *right;

static int cmpEnt(const void*a,const void*b){
    const Ent*x=a,*y=b;
    for(int i=0;i<DLEN;i++){ if(x->d[i]<y->d[i])return -1; if(x->d[i]>y->d[i])return 1; }
    return 0;
}
static int cmpD(const uint32_t*a,const uint32_t*b){
    for(int i=0;i<DLEN;i++){ if(a[i]<b[i])return -1; if(a[i]>b[i])return 1; }
    return 0;
}

int main(void){
    FILE*fp=fopen("/app/pairs.txt","r");
    if(!fp){perror("pairs");return 1;}
    for(int i=0;i<NPAIR;i++){
        unsigned long long p,c;
        if(fscanf(fp,"%llu %llu",&p,&c)!=2){fprintf(stderr,"read err %d\n",i);return 1;}
        P_L[i]=(p>>32)&0xFFFFFFFF; P_R[i]=p&0xFFFFFFFF;
        C_L[i]=(c>>32)&0xFFFFFFFF; C_R[i]=c&0xFFFFFFFF;
        L0[i]=P_L[i];            R0[i]=P_R[i]^P_L[i];
        R4[i]=C_L[i];            L4[i]=C_R[i]^C_L[i];
    }
    fclose(fp);

    left=malloc(sizeof(Ent)*NSEED);
    right=malloc(sizeof(Ent)*NSEED);

    /* left: seed0 -> P_i = L2_i = L0_i ^ f(R0_i ^ k0); D_i = P_i ^ P_0 */
    for(uint32_t s=0;s<NSEED;s++){
        uint32_t k0=expand(s);
        uint32_t P0=L0[0]^f_function(R0[0]^k0);
        for(int i=1;i<SIGP;i++){
            uint32_t Pi=L0[i]^f_function(R0[i]^k0);
            left[s].d[i-1]=Pi^P0;
        }
        left[s].seed=s;
    }
    /* right: seed3 -> Q_i = finv(R2_i ^ R0_i), R2_i = R4_i ^ f(L4_i ^ k3); D_i = Q_i ^ Q_0 */
    for(uint32_t s=0;s<NSEED;s++){
        uint32_t k3=expand(s);
        uint32_t R2_0=R4[0]^f_function(L4[0]^k3);
        uint32_t Q0=finv(R2_0^R0[0]);
        for(int i=1;i<SIGP;i++){
            uint32_t R2i=R4[i]^f_function(L4[i]^k3);
            uint32_t Qi=finv(R2i^R0[i]);
            right[s].d[i-1]=Qi^Q0;
        }
        right[s].seed=s;
    }
    qsort(left,NSEED,sizeof(Ent),cmpEnt);
    qsort(right,NSEED,sizeof(Ent),cmpEnt);

    /* merge match */
    long li=0,ri=0;
    int found=0;
    uint32_t fs0=0,fs1=0,fs2=0,fs3=0;
    while(li<NSEED && ri<NSEED && !found){
        int c=cmpD(left[li].d,right[ri].d);
        if(c<0){li++;continue;}
        if(c>0){ri++;continue;}
        /* block of equal D on both sides */
        long lj=li; while(lj<NSEED && cmpD(left[lj].d,left[li].d)==0) lj++;
        long rj=ri; while(rj<NSEED && cmpD(right[rj].d,right[ri].d)==0) rj++;
        for(long a=li;a<lj && !found;a++) for(long b=ri;b<rj && !found;b++){
            uint32_t seed0=left[a].seed, seed3=right[b].seed;
            uint32_t k0=expand(seed0), k3=expand(seed3);
            /* compute L2,R2 for all pairs, derive k1,k2, verify */
            uint32_t L2[NPAIR],R2[NPAIR];
            for(int i=0;i<NPAIR;i++){
                L2[i]=L0[i]^f_function(R0[i]^k0);
                R2[i]=R4[i]^f_function(L4[i]^k3);
            }
            uint32_t k1=L2[0]^finv(R2[0]^R0[0]);
            uint32_t k2=R2[0]^finv(L4[0]^L2[0]);
            int ok=1;
            for(int i=0;i<NPAIR;i++){
                if(f_function(L2[i]^k1)!=(R2[i]^R0[i])){ok=0;break;}
                if(f_function(R2[i]^k2)!=(L4[i]^L2[i])){ok=0;break;}
            }
            if(!ok) continue;
            /* find seeds for k1,k2 */
            uint32_t seed1=0xFFFFFFFF,seed2=0xFFFFFFFF;
            for(uint32_t s=0;s<NSEED;s++){ if(expand(s)==k1){seed1=s;break;} }
            for(uint32_t s=0;s<NSEED;s++){ if(expand(s)==k2){seed2=s;break;} }
            if(seed1==0xFFFFFFFF||seed2==0xFFFFFFFF) continue;
            fs0=seed0;fs1=seed1;fs2=seed2;fs3=seed3;found=1;
        }
        li=lj; ri=rj;
    }
    if(!found){fprintf(stderr,"NO MATCH\n");return 2;}
    printf("%05X %05X %05X %05X\n",fs0,fs1,fs2,fs3);
    return 0;
}

